import React from 'react';
import { Link } from 'react-router-dom';

const Footer = () => {
    const currentYear = new Date().getFullYear();

    return (
        <footer style={styles.footerContainer}>
            <div style={styles.contentWrapper}>
                {/* Texto de Copyright principal */}
                <p style={styles.copyrightText}>
                    © {currentYear} Repositorio Bicentenario de Bolivia. Todos los derechos reservados.
                </p>

                <div style={styles.mainContentFlex}>

                    {/* Columna 1: Navegación */}
                    <div style={styles.section}>
                        <h3 style={styles.sectionTitle}>NAVEGACIÓN</h3>
                        <ul style={styles.linkList}>
                            <li><Link to="/acerca-de" style={styles.link}>Acerca de</Link></li> {/* Nuevo enlace */}
                            <li><Link to="/mas-de-nosotros" style={styles.link}>Más de Nosotros</Link></li> {/* Nuevo enlace */}
                            <li><Link to="/contacto" style={styles.link}>Contacto</Link></li> {/* Mantenemos contacto */}
                        </ul>
                    </div>

                    {/* Columna 2: Redes Sociales (al medio) */}
                    <div style={styles.socialSection}> {/* Estilo específico para centrar y manejar iconos */}
                        <h3 style={styles.sectionTitle}>REDES SOCIALES</h3>
                        <div style={styles.socialIcons}>
                            {/* **IMPORTANTE:** Asegúrate de que estos archivos PNG existan en public/media/icons/ */}
                            <a href="https://www.facebook.com/TuPaginaDeFacebook" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/facebook_icon.png" alt="Facebook" style={styles.socialIconImage} />
                            </a>
                            <a href="https://www.instagram.com/TuCuentaDeInstagram" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/instagram_icon.png" alt="Instagram" style={styles.socialIconImage} />
                            </a>
                            <a href="https://www.tiktok.com/@TuCuentaDeTikTok" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/tiktok_icon.png" alt="TikTok" style={styles.socialIconImage} />
                            </a>
                        </div>
                    </div>

                </div>

                {/* Línea divisoria */}
                <div style={styles.divider}></div>

                {/* Cita final */}
                <p style={styles.quoteText}>
                    “Conocer nuestra historia es entender nuestro presente.”
                </p>

                {/* Crédito de Alberto Navarro */}
                <p style={styles.navarroCredit}>Titulizado por Alberto Navarro</p>

            </div>
        </footer>
    );
};

const styles = {
    footerContainer: {
        backgroundColor: '#F8F6F1', // Un beige suave como color de fondo fijo
        color: '#4a4a4a', // Color de texto principal
        fontFamily: "'Inter', sans-serif", // Fuente que imita el estilo moderno
        padding: '20px 0 15px 0', // Padding vertical ajustado para compactar
        marginTop: 'auto', // Para que se pegue al final de la página
        boxShadow: '0 -2px 8px rgba(0,0,0,0.02)', // Sombra muy sutil en la parte superior
        fontSize: '0.85rem', // Tamaño de fuente general
        lineHeight: '1.4',
        minHeight: '150px', // Altura mínima para que no sea *demasiado* pequeño
        display: 'flex', // Para centrar el contenido verticalmente
        alignItems: 'center', // Centra el contenido verticalmente
    },
    contentWrapper: {
        maxWidth: '700px', // Ancho máximo del contenido, para hacerlo más compacto
        margin: '0 auto',
        padding: '0 15px', // Padding horizontal
        textAlign: 'center', // Centra todo el texto por defecto
        width: '100%',
    },
    copyrightText: {
        fontSize: '0.8rem', // Tamaño de copyright
        color: '#555',
        marginBottom: '15px', // Espacio abajo del copyright
        textAlign: 'center',
        fontWeight: 'normal',
    },
    mainContentFlex: {
        display: 'flex',
        flexWrap: 'wrap', // Permite que las columnas se envuelvan en pantallas pequeñas
        justifyContent: 'center', // Centra las secciones en el contenedor
        gap: '30px', // Mayor espacio entre las secciones
        marginBottom: '15px', // Espacio entre las secciones y la línea divisoria
    },
    section: {
        flex: '0 0 auto', // Permite que la sección ajuste su tamaño al contenido
        padding: '5px 10px',
        textAlign: 'center',
    },
    socialSection: { // Estilo específico para la sección de redes sociales (que va en medio)
        flex: '0 0 auto',
        padding: '5px 10px',
        textAlign: 'center',
        minWidth: '150px', // Asegura que la sección de redes sociales tenga un ancho mínimo
    },
    sectionTitle: {
        fontSize: '0.9rem', // Títulos ligeramente más pequeños
        fontWeight: 'bold',
        marginBottom: '8px',
        textTransform: 'uppercase',
        color: '#222',
    },
    linkList: {
        listStyle: 'none',
        padding: 0,
        margin: 0,
        lineHeight: '1.2', // Reduce el espaciado entre ítems de la lista
    },
    link: {
        textDecoration: 'none',
        color: '#555',
        fontSize: '0.8rem', // Tamaño de fuente para enlaces
        transition: 'color 0.2s ease',
        display: 'inline-block',
        '&:hover': {
            color: '#1e7e34', // Un verde
        },
    },
    socialIcons: {
        display: 'flex',
        justifyContent: 'center', // Centrar los íconos dentro de su contenedor
        gap: '15px', // Espacio entre los íconos
        marginTop: '5px',
    },
    socialIconLink: {
        textDecoration: 'none',
        display: 'inline-block',
    },
    socialIconImage: {
        width: '20px', // Tamaño de íconos
        height: '20px',
        opacity: 0.8,
        transition: 'opacity 0.2s ease, transform 0.1s ease',
        '&:hover': {
            opacity: 1,
            transform: 'scale(1.1)',
        },
    },
    divider: {
        borderBottom: '1px solid rgba(200,200,200,0.4)', // Línea divisoria sutil
        width: '70%', // Ancho de la línea
        margin: '15px auto 10px auto', // Centrar y espacio
    },
    quoteText: {
        fontSize: '0.75rem', // Tamaño de fuente para la cita
        fontStyle: 'italic',
        color: '#777',
        margin: '0 0 5px 0',
        textAlign: 'center',
    },
    navarroCredit: {
        fontSize: '0.65rem', // Pequeño y discreto
        color: '#888',
        marginTop: '0',
        textAlign: 'center',
    }
};

export default Footer;
